(()=>{var t="zrp-wallet-bridge";window.addEventListener("message",async n=>{if(n.source!==window)return;let o=n.data;if(!o||o.tag!==t||o.direction!=="to-content")return;let{requestId:i,type:r,payload:a}=o;try{let e=await chrome.runtime.sendMessage({type:r,origin:window.location.origin,...a});window.postMessage({tag:t,direction:"to-page",requestId:i,response:e},window.location.origin)}catch(e){window.postMessage({tag:t,direction:"to-page",requestId:i,response:{ok:!1,error:e.message||String(e)}},window.location.origin)}});})();
